import './TimePicker.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ChangeEvent } from 'react';
import React, { forwardRef, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import { Icon } from '../Icon';
import { TextField } from '../TextField';
import type { TimePickerProps } from './TimePicker.types';

export const TimePicker = forwardRef<HTMLInputElement, TimePickerProps>(
	(
		{
			className,
			hidePicker = true,
			showPlaceholder = true,
			showIcon = true,
			disabled = false,
			dataTestId = 'TimePicker',
			step = '60',
			onChange,
			error = false,
			fullWidth,
			defaultValue = '',
			...restProps
		},
		forwardedRef,
	) => {
		const [inputValue, setInputValue] = useState<string>(defaultValue);
		const [isFocused, setIsFocused] = useState<boolean>(false);

		const handleInputChange = (event: ChangeEvent<HTMLInputElement>): void => {
			setInputValue(event.target.value);

			onChange?.(event.target.value);
		};

		const handleInputFocus = (event: ChangeEvent<HTMLInputElement>): void => {
			setIsFocused(true);
		};
		const handleInputBlur = (event: ChangeEvent<HTMLInputElement>): void => {
			setIsFocused(false);
		};

		return (
			<div
				data-testid={dataTestId}
				className={classNames('dsb_timepicker', fullWidth && 'dsb_timepicker__full-width', className)}
			>
				{showIcon && <Icon iconName={Icons.Clock} className="dsb_timepicker__clock-icon" />}
				<TextField
					ref={forwardedRef}
					className={classNames(
						'dsb_timepicker__input',
						hidePicker && 'dsb_timepicker__input--hide-picker',
						showPlaceholder && !isFocused && !inputValue && !error && 'dsb_timepicker__input--placeholder',
						fullWidth && 'dsb_timepicker__input--full-width',
						className,
					)}
					value={inputValue}
					onBlur={handleInputBlur}
					onFocus={handleInputFocus}
					onChange={handleInputChange}
					type="time"
					step={step}
					required
					disabled={disabled}
					error={error}
					{...restProps}
				/>
			</div>
		);
	},
);

TimePicker.displayName = 'TimePicker';
